`celldefine 
module NAND3BV3_12TH40 ( ZN, A1, B1, B2, VDD, VSS); 
input A1, B1, B2;
inout VDD, VSS;
output ZN;
wire ZN_temp;

      not  I1(A1_inv, A1 );
      nand I0(ZN_temp, A1_inv, B1, B2 );
  assign ZN = ((VDD === 1'b1) && (VSS === 1'b0)) ? ZN_temp : 1'bx;
  `ifdef functional // functional // 
 
  `else // functional // 
 
  specify 
 
 	// arc A1 --> ZN
	 (A1 => ZN) = (1.0,1.0);

	// arc B1 --> ZN
	 (B1 => ZN) = (1.0,1.0);

	// arc B2 --> ZN
	 (B2 => ZN) = (1.0,1.0);

 
  endspecify 
 
  `endif // functional // 
endmodule
`endcelldefine
