  input D, RDN, CK;

inout VDD, VSS;
  output QN;
wire QN_temp;

  reg NOTIFIER;
  supply1 xSN;
wire ENABLE_D;
  buf   XX0 (xRN, RDN );
  buf     IC (clk, CK );
  udp_dff_PWR I0 (n0, D, clk, xRN, xSN, VDD, VSS, NOTIFIER ); 
  not     I2 (QN_temp, n0 );
  assign ENABLE_D= (D) ? 1'b1:1'b0;
  assign QN = ((VDD === 1'b1) && (VSS === 1'b0)) ? QN_temp : 1'bx;
  `ifdef functional // functional //

  `else // functional //
    buf SMC_I5(ENABLE_RDN,RDN);


  specify


	// arc CK --> QN
	(posedge CK => (QN : D))  = (1.0,1.0);

	if(CK===1'b0 && D===1'b0)
