      1    *    1     ?   1   ?   ?   1      0     ?  : 1  :  1 ; 
      1    x    1     ?   1   ?   ?   1      0     ?  : 1  :  1 ; 
      ?  (10)   ?     ?   ?   ?   ?   1      0     ?  : ?  :  -;  // no changes on falling clk edge
      ?  (x0)   ?     ?   ?   ?   ?   1      0     ?  : ?  :  -;  // no changes on falling clk edge
