   output out;  
   input  r_, s_, VDD, VSS, NOTIFIER;
   reg    out;

   table

// r_  s_  VDD  VSS  NOT : Qt : Qt+1
// 
  (?1) 1   1   0   ?   : ?  :  -  ; // no change
   1  (?1) 1   0   ?   : ?  :  -  ; // no change
  (?0) 1   1   0   ?   : ?  :  0  ; // reset
   0  (?1) 1   0   ?   : ?  :  0  ; // reset
   ?   0   1   0   ?   : ?  :  1  ; // unused state
  (?1) x   1   0   ?   : 1  :  1  ; // reduced pessimism
   1  (?x) 1   0   ?   : 1  :  1  ; // reduced pessimism
  (?x) 1   1   0   ?   : 0  :  0  ; // reduced pessimism
   x  (?1) 1   0   ?   : 0  :  0  ; // reduced pessimism
   ?   ?   0   1   ?   : ?  :  x  ; 
   ?   ?   0   0   ?   : ?  :  x  ; 
   ?   ?   1   1   ?   : ?  :  x  ; 
   ?   ?   ?   ?   *   : ?  :  x  ; // any NOTIFIER changed

   endtable
endprimitive // udp_rslatn_out

