   ?  1   1   *   1   0   ?   : 1  :  1  ; // cover all transistions on set_
   1  ?   1   *   1   0   ?   : 1  :  1  ; // cover all transistions on set_
   ?  ?   0   1   1   0   ?   : ?  :  0  ; // reset output
   ?  1   *   1   1   0   ?   : 0  :  0  ; // cover all transistions on clr_
   0  ?   *   1   1   0   ?   : 0  :  0  ; // cover all transistions on clr_
